#include <omp.h>
#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <limits.h>
#include <sys/time.h>
#include <math.h>
#include <stdbool.h>
#include <stdint.h>

#include "../common.h"
#include "../util/timer/timer.h"
#ifdef TIMING
#include "../../util/timing.h"
#endif

#include "./kernel_gpu_opencl_wrapper.h"

// Provide the kernel_cpu implementation required by the linker
void 
kernel_cpu(	int cores_arg,
			record *records,
			knode *knodes,
			long knodes_elem,
			int order,
			long maxheight,
			int count,
			long *currKnode,
			long *offset,
			int *keys,
			record *ans)
{
	// Use the same logic as the OpenMP wrapper
	int local_work_size = order < 1024 ? order : 1024;

	#pragma omp parallel num_threads(count)
	{
		int bid = omp_get_thread_num();
		int thid;
		long current_knode = currKnode[bid];
		long offset_val = offset[bid];
		int key_val = keys[bid];

		for (thid = 0; thid < local_work_size; thid++) {
			int i;
			for(i = 0; i < maxheight; i++){
				if((knodes[current_knode].keys[thid]) <= key_val && (knodes[current_knode].keys[thid+1] > key_val)){
					if(knodes[offset_val].indices[thid] < knodes_elem){
						offset_val = knodes[offset_val].indices[thid];
					}
				}

				if(thid==0){
					current_knode = offset_val;
				}
			}
		}

		// Search for the key in the final node
		ans[bid].value = -1; // Default if not found
		for (thid = 0; thid < local_work_size; thid++) {
			if(knodes[current_knode].keys[thid] == key_val){
				ans[bid].value = records[knodes[current_knode].indices[thid]].value;
				break;
			}
		}
	}
}

void 
kernel_gpu_opencl_wrapper(	record *records,
							long records_mem,
							knode *knodes,
							long knodes_elem,
							long knodes_mem,

							int order,
							long maxheight,
							int count,

							long *currKnode,
							long *offset,
							int *keys,
							record *ans)
{

#ifdef TIMING
	struct timeval tv;
	struct timeval tv_total_start, tv_total_end;
	struct timeval tv_init_end;
	struct timeval tv_h2d_start, tv_h2d_end;
	struct timeval tv_d2h_start, tv_d2h_end;
	struct timeval tv_kernel_start, tv_kernel_end;
	struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
	struct timeval tv_close_start, tv_close_end;
	float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time= 0,
		  d2h_time = 0, close_time = 0, total_time = 0;
#endif

#ifdef  TIMING
    gettimeofday(&tv_total_start, NULL);
#endif

#ifdef  TIMING
	gettimeofday(&tv_init_end, NULL);
	tvsub(&tv_init_end, &tv_total_start, &tv);
	init_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

#ifdef  TIMING
	gettimeofday(&tv_mem_alloc_end, NULL);
	tvsub(&tv_mem_alloc_end, &tv_init_end, &tv);
	mem_alloc_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

#ifdef  TIMING
	gettimeofday(&tv_h2d_start, NULL);
#endif
	// Data is already in host memory, no transfer needed for OpenMP
#ifdef  TIMING
	gettimeofday(&tv_h2d_end, NULL);
	tvsub(&tv_h2d_end, &tv_h2d_start, &tv);
	h2d_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

#ifdef  TIMING
	gettimeofday(&tv_kernel_start, NULL);
#endif

	// Call the CPU implementation which uses OpenMP
	kernel_cpu(1, records, knodes, knodes_elem, order, maxheight, count, currKnode, offset, keys, ans);

#ifdef  TIMING
	gettimeofday(&tv_kernel_end, NULL);
	tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
	kernel_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

#ifdef  TIMING
	gettimeofday(&tv_d2h_start, NULL);
#endif
	// Data is already in host memory
#ifdef  TIMING
	gettimeofday(&tv_d2h_end, NULL);
	tvsub(&tv_d2h_end, &tv_d2h_start, &tv);
	d2h_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

#ifdef  TIMING
	gettimeofday(&tv_close_start, NULL);
#endif

#ifdef  TIMING
	gettimeofday(&tv_close_end, NULL);
	tvsub(&tv_close_end, &tv_close_start, &tv);
	close_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
    tvsub(&tv_close_end, &tv_total_start, &tv);
    total_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

#ifdef TIMING
	printf("Time spent in different stages of GPU_CUDA KERNEL:\n");
	printf("Init: %f\n", init_time);
	printf("MemAlloc: %f\n", mem_alloc_time);
	printf("HtoD: %f\n", h2d_time);
	printf("Exec: %f\n", kernel_time);
	printf("DtoH: %f\n", d2h_time);
	printf("Close: %f\n", close_time);
	printf("Total: %f\n", total_time);
#endif

}

