#include "./kernel_gpu_opencl_wrapper_2.h"

// Provide the kernel_cpu_2 implementation required by the linker
void 
kernel_cpu_2(	int cores_arg,
				knode *knodes,
				long knodes_elem,
				int order,
				long maxheight,
				int count,
				long *currKnode,
				long *offset,
				long *lastKnode,
				long *offset_2,
				int *start,
				int *end,
				int *recstart,
				int *reclength)
{
	// Use the same logic as the OpenMP wrapper
	int local_work_size = order < 1024 ? order : 1024;

	#pragma omp parallel num_threads(count)
	{
		int bid = omp_get_thread_num();
		int thid;
		long current_knode = currKnode[bid];
		long last_knode = lastKnode[bid];
		long offset_val = offset[bid];
		long offset_2_val = offset_2[bid];
		int start_val = start[bid];
		int end_val = end[bid];

		for (thid = 0; thid < local_work_size; thid++) {
			int i;
			for(i = 0; i < maxheight; i++){
				if((knodes[current_knode].keys[thid] <= start_val) && (knodes[current_knode].keys[thid+1] > start_val)){
					if(knodes[current_knode].indices[thid] < knodes_elem){
						offset_val = knodes[current_knode].indices[thid];
					}
				}
				if((knodes[last_knode].keys[thid] <= end_val) && (knodes[last_knode].keys[thid+1] > end_val)){
					if(knodes[last_knode].indices[thid] < knodes_elem){
						offset_2_val = knodes[last_knode].indices[thid];
					}
				}

				if(thid==0){
					current_knode = offset_val;
					last_knode = offset_2_val;
				}
			}
		}

		// Find start record
		recstart[bid] = -1;
		for (thid = 0; thid < local_work_size; thid++) {
			if(knodes[current_knode].keys[thid] == start_val){
				recstart[bid] = knodes[current_knode].indices[thid];
				break;
			}
		}

		// Find length
		reclength[bid] = 0;
		if (recstart[bid] != -1) {
			for (thid = 0; thid < local_work_size; thid++) {
				if(knodes[last_knode].keys[thid] == end_val){
					reclength[bid] = knodes[last_knode].indices[thid] - recstart[bid] + 1;
					break;
				}
			}
		}
	}
}

