	// Call the CPU implementation which uses OpenMP
	kernel_cpu_2(1, knodes, knodes_elem, order, maxheight, count, currKnode, offset, lastKnode, offset_2, start, end, recstart, reclength);

#ifdef  TIMING
	gettimeofday(&tv_kernel_end, NULL);
	tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
